var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"너무 어두워져서……. 아무것도 보이질 않아요.","JPN":"暗すぎて……何も見えません。","ENG":"It’s too dark in here... I can’t see anything.","TWN":"突然變得好暗……什麼都看不清楚。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"통신 상태도 먹통이야. 이래선 외부와 연락하기 어렵겠어.","JPN":"通信も繋がらない。これじゃ外部との連絡は厳しいな。","ENG":"Communication is blocked as well. We lost contact with the outside.","TWN":"而且也沒有任何訊號，根本無法與外界聯繫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"우선은……. 다들 이것부터 쓰지. 야간 투시경이야.","JPN":"とりあえず……みんなこれを使ってくれ。暗視スコープだ。","ENG":"Well, first things first... use this. Night-vision goggles.","TWN":"我看……大家還是先戴上夜視鏡吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 감사합니다.","JPN":"あ、ありがとうございます。","ENG":"Oh, thank you.","TWN":"好，謝謝。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"준비성이 꽤 철저한데. 다시 봤어, 메이슨 씨.","JPN":"ずいぶん準備がいいな。メイソンさんのこと見直したぜ。","ENG":"You’re a very thorough person. That’s impressive, Mr. Mason.","TWN":"準備得滿周到的嘛！令人刮目相看喔，梅森！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"여기는…….","JPN":"ここは……","ENG":"This place...","TWN":"這裡是……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"생각보다 훨씬 넓군. 단순한 보급 시설은 아닌 것 같은데.","JPN":"思ったよりもずっと広いな。単なる補給施設ではなさそうだ。","ENG":"It’s much bigger than I thought. This doesn’t look like an ordinary supply depot.","TWN":"比想像中還寬敞，應該不是單純的補給設施吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"뭐, 그래 봤자 버려진 곳이지.","JPN":"まあ、だとしても、今は捨てられた地に過ぎないさ。","ENG":"Still, it’s an abandoned facility.","TWN":"嗯，反正就是個荒廢的地方。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"각자 흩어져서 수색해 보자고. 이런 곳에서 오래 머물 필요는 없으니까.","JPN":"みんなで手分けして捜索してみよう。\\nこんな所、長居する必要はないからな。","ENG":"Let’s spread out and search. We don’t want to stay here too long.","TWN":"大家分頭去找吧，我們不要在這裡逗留太久。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"잠깐, 대령.","JPN":"ちょっと待て、大佐。","ENG":"Wait, Colonel.","TWN":"上校，先等一下。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"왜 그러지, 메이슨 씨?","JPN":"メイソンさん、どうした？","ENG":"What is it, Mr. Mason?","TWN":"怎麼了嗎，梅森？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"리플레이서…… 아니, 제이나 양이 뭔가 이상해.","JPN":"リプレイサー……いや、ジェイナの様子が何かおかしい。","ENG":"The Replacer—I mean, Jaina is acting strange.","TWN":"克隆……不是，婕娜好像怪怪的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"……이게 바로 그 노바급 리액터로군요.","JPN":"……これがあのノヴァ級リアクターなんですね。","ENG":"... So this is the Nova-Class Reactor.","TWN":"……這就是諾瓦反應爐嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"아직 불완전한 미스틸테인의 동력원으로 사용하면 우리에게 큰 힘이 될 겁니다.","JPN":"まだ不完全なミスティルテインの動力源として使えば、\\n我々にとって大きな力となるでしょう。","ENG":"This will be a great help for us if we use it as a power source for the imperfect Misteltein.","TWN":"米斯特丁還不完全，或許可以拿來當作它的動能，對我們應該會是一大助力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"……아니, 노바급 리액터는 이대로 여기 동결할 생각이네.","JPN":"……いや、ノヴァ級リアクターはこのままここに凍結させるつもりだ。","ENG":"No, I’m going to freeze the Nova-Class Reactor here and now.","TWN":"……不，我打算將諾瓦反應爐就冷凍在這裡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"네? 그건 어째서……?","JPN":"えっ？　それはどうして……？","ENG":"Huh? But why?","TWN":"什麼？為什麼……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"이유를 알고 싶습니다, 부사령관님.","JPN":"理由を教えてください、副司令官。","ENG":"I want to know the reason, Deputy Commander.","TWN":"副司令官，我想知道理由。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"첫 번째 이유는 불가능하기 때문이지.","JPN":"まず第一に不可能だからだ。","ENG":"First, it’s impossible for us to handle it.","TWN":"第一個理由是因為不可能。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"현재 우리의 기술로는 노바급 리액터를 제대로 다룰 수 없어.","JPN":"現在の我々の技術では、ノヴァ級リアクターをまともに扱うことができない。","ENG":"Our current tech isn’t able to handle this device properly.","TWN":"以我們現在的技術，是無法完全控制諾瓦反應爐的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"함부로 테크 레벨 5의 무기인 미스틸테인에 장착하려고 했다간 둘 다 파괴되고 말 테지.","JPN":"下手にテックレベル5の武器であるミスティルテインに装着しようとすれば、\\n両方とも壊れてしまうだろう。","ENG":"If we try to attach it to Tech Level 5 Misteltein, we will lose them both.","TWN":"如果隨隨便便就裝載在技術等級5的武器上，恐怕最後會落個兩頭空的下場。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"대폭발과 함께.","JPN":"大爆発と共にな。","ENG":"In a huge explosion.","TWN":"而且可能還會引發大爆炸。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"부사령관님, 하지만……!","JPN":"副司令官、しかし……！","ENG":"But Deputy Commander...","TWN":"副司令官，可是……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"또 다른 이유가 있네. 가장 중요한 이유지.","JPN":"もう一つ別の理由がある。これが最も重要な理由だ。","ENG":"And here comes the second reason. It’s much more important.","TWN":"另外還有一個理由，這才是最重要的理由。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그건…… 무엇입니까?","JPN":"それは……何でしょう？","ENG":"What is it?","TWN":"是……什麼理由？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이걸 사용한다고 해도, 겨우 무기 하나일 뿐이야.","JPN":"これを使ったとしても、たかが武器の一つに過ぎない。","ENG":"Even if we succeed with Misteltein, it’s just a single weapon.","TWN":"就算使用它，也不過就是一個武器。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"세상을 지키려면 그보다 많은 무기가 필요하지.","JPN":"世界を守るためには、より多くの武器が必要だ。","ENG":"To protect the world, we need many more weapons.","TWN":"但守護世界需要很多的武器！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"아주 많은 무기가…….","JPN":"そう、より多くの武器が……","ENG":"A lot of weapons...","TWN":"非常多的武器……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"일회성으로 소모해서는 안 될 기술일세.","JPN":"使い捨てにしてはならない技術だ。","ENG":"It would be a waste to use the reactor once and lose it forever.","TWN":"這樣一次就把它用掉太可惜，"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"양산할 수 있는 수단이 생겼을 때 사용하는 게 맞겠지.","JPN":"量産可能な手段ができた時に使うべきだろう。","ENG":"It’s better to keep it safe until we secure the means of mass-production.","TWN":"必須等到研究出可以大量生產的方法後再使用。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그 날이 올 때까지, 이건 여기에 숨겨 두겠네.","JPN":"その日が来るまで、これはここに隠しておこう。","ENG":"So I’m keeping it here, until the day comes.","TWN":"所以在那一天到來前，我打算把它藏在這裡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"만약 내가 먼저 부재하게 되는 경우에는……. 자네에게 뒷일을 맡기도록 하지.","JPN":"もし私が先にいなくなることがあれば……後のことは君に任せよう。","ENG":"And if I’m not there at the moment... I want you to take care of it instead of me.","TWN":"萬一我早一步離開……那這件事就交給你負責。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"Huff, huff...","TWN":"呼呼……呼呼……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이봐, 괜찮은가? 땀이 비 오듯이 흐르는데?","JPN":"おい、大丈夫か？　汗が滝のように流れているが。","ENG":"Hey, are you okay? You’re sweating.","TWN":"喂，你還好吧？你流好多汗！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"죄송해요……. 기억이…… 갑자기 떠오르는 바람에…….","JPN":"ごめんなさい……記憶を……急に取り戻したので……","ENG":"I’m sorry... A memory just returned...","TWN":"不好意思……我突然……想起一些事……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"좋은 소식이군.","JPN":"それは良いニュースだな。","ENG":"That’s good news.","TWN":"很好啊！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"하지만 리플레이서 퀸의 인격이 되살아나는 건 곤란해.","JPN":"だが、リプレイサー・クイーンの人格が蘇るのは困る。","ENG":"I hope it didn’t come with the Replacer Queen’s personality though.","TWN":"但要是克隆·女皇的人格復活的話可就不好囉！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그런 일이 벌어지면 어떻게 될지는 본인이 더 잘 알고 있겠지?","JPN":"そんなことが起きたらどうなるか、本人が一番よくわかっているだろう？","ENG":"Because you know what will happen if that occurs.","TWN":"萬一真的發生這種事，你應該知道會有什麼下場吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그야…… 잘 알고 있어요.","JPN":"それは……よくわかっています。","ENG":"I... I’m aware of it.","TWN":"我……當然知道。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저는 그런 식으로 허무하게 사라지고 싶지는 않으니까요.","JPN":"私はそんな風に虚しく消えたくありません。","ENG":"I don't want to be gone in vain like that.","TWN":"因為我並不想用那種方式消失在這個世界上。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"좋아. 살벌한 이야기는 그쯤 해 둬.","JPN":"よし。そんな怖い話はその辺にしておいて……","ENG":"Hey, ease up, alright?","TWN":"好了好了，威嚇的話就到此為止。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"뭔가 알아낸 게 있나?","JPN":"何か思い出したことはあるか？","ENG":"So what do you remember?","TWN":"那你有想起什麼嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네. 노바급 리액터는 이 시설에 동결되어 있어요.","JPN":"はい。ノヴァ級リアクターはこの施設に凍結されています。","ENG":"The Nova-Class Reactor is actually here, frozen.","TWN":"嗯，諾瓦反應爐就冷凍在這個設施裡。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……식별명, 퀸. 시설의 휴면 상태를 해제하세요.","JPN":"……識別名、クイーン。施設の休眠状態を解除してください。","ENG":"ID, Queen. Unlock the facility.","TWN":"……識別姓名，女皇。我要解除設施的休眠狀態。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"신원 확인이 완료되었습니다. 무엇이 필요하십니까, 퀸.","JPN":"身元確認が完了しました。どのようなご用件でしょうか、クイーン。","ENG":"ID confirmed. What do you need, Queen?","TWN":"身分識別完畢。請問需要什麼服務？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그 여자의……. 아니, 제 권한으로 동결 처리된 노바급 리액터를 회수하겠습니다.","JPN":"あの女の……いえ、私の権限で、凍結されているノヴァ級リアクターを回収します。","ENG":"On her—I mean, my authority, I want to cancel the order freezing the Nova-Class Reactor.","TWN":"我以那個女的……不，是以為我的權限，要求取回冷凍中的諾瓦反應爐。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"명령권 확인. 노획 방지용 기폭 장치를 해제합니다.","JPN":"命令権を確認。鹵獲防止用の起爆装置を解除します。","ENG":"Authority level confirmed. Defense explosives disarmed.","TWN":"指令確認，解除防盜引爆裝置。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……설마 합중국 한복판에 있었나. 이면세계에 숨겨 뒀을지도 모른다고 생각했는데.","JPN":"……まさか合衆国のど真ん中にあったとは。\\n裏世界に隠していたと思ったのにな。","ENG":"They stored it right in the middle of the States? I thought maybe they kept it in the Counterside.","TWN":"……竟然就在合眾國的正中心？我原本還猜會不會藏在異界呢？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그래. 리플레이서 킹도 사람들이 그쪽처럼 생각한다는 걸 노린 거겠지.","JPN":"ああ、リプレイサー・キングもそう思われることを狙ったんだろう。","ENG":"I guess that’s what the Replacer King wanted you all to think.","TWN":"是啊，克隆·帝皇應該也有猜到你們會這麼想，才故意藏在這裡的吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"보고드립니다. 노바급 리액터의 동결 해제가 완료되었습니다.","JPN":"ご報告いたします。ノヴァ級リアクターの凍結解除が完了しました。","ENG":"Cancellation of Nova-Class Reactor freeze complete.","TWN":"報告，諾瓦反應爐解凍完畢。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L29_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"휴우…….","JPN":"ふう……","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"자료에 나와 있던 그대로군. 이제 부대로 복귀하기만 하면 되겠어.","JPN":"資料に示されていたとおりだな。これでようやく部隊に復帰できるぞ。","ENG":"It’s just as the document says. Now we just have to go back to HQ.","TWN":"和資料上寫的一樣，把它帶回部隊吧！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"대령, 혹시나 싶어서 하는 말인데 잔금은 잊지 않았겠지?","JPN":"大佐、念のため聞くが残金のことは忘れてないよな？","ENG":"Colonel, you haven’t forgotten my payment, have you?","TWN":"上校，我只是提醒一下，你應該沒忘記還有尾款吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"물론이지, 메이슨 씨.","JPN":"もちろんだ、メイソンさん。","ENG":"Of course not, Mr. Mason.","TWN":"當然記得囉！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"일이 깔끔하게 끝난 기념으로 내가 돌아가는 길에 술 한 잔 정도는 살 수도……","JPN":"任務がすんなり終わった記念に、帰りに俺が一杯くらい奢ってやっても……","ENG":"Now that everything is wrapped up, I could buy you a drink on the way back—","TWN":"看在事情這麼順利的份上，我回程還可以請你喝一杯……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"음?","JPN":"うん……？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L40_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"경고. 신원 불명의 침입자가 감지되었습니다.","JPN":"警告。身元不明の侵入者を検知しました。","ENG":"Warning. Unidentified intruder confirmed.","TWN":"警告，感應到陌生的侵入者。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"보안 시스템 기동 불가. 대응 필요.","JPN":"セキュリティシステム起動不可。対応が必要です。","ENG":"Unable to run security system. Action required.","TWN":"無法啟動安全系統，需進行應對。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"누군지 몰라도 초인종 누를 생각은 없는 것 같군.","JPN":"誰だか知らないが、チャイムくらいは鳴らせよな。","ENG":"This intruder certainly doesn’t want to ring the doorbell.","TWN":"不知道是誰，怎麼這麼沒禮貌，起碼該按個電鈴吧！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"불청객은 내가 막겠다. 그 틈에 어서 리액터를 회수해.","JPN":"招かれざる客は俺が相手をしよう。その間に早くリアクターを回収してくれ。","ENG":"I’ll go stop the uninvited guest. You retrieve the reactor.","TWN":"不速之客就交給我，你們找機會帶走反應爐！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 네!","JPN":"あっ、はい！","ENG":"Oh, okay!","TWN":"嗯，好的！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"찾았다.","JPN":"……見つけたぞ。","ENG":"I found you.","TWN":"找到了。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……뭐야? 어린애잖아?","JPN":"……何だ、子どもじゃないか。","ENG":"... A girl?","TWN":"……搞什麼？竟然是個小丫頭？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"복장도 꽤나 시대착오적인 것 같은데.","JPN":"服装もだいぶ時代遅れだと思うが。","ENG":"With a very classic garment.","TWN":"穿著是不是也有點復古？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"설마 말로만 듣던 조디악 나이츠의 신입 대원이라도 되는 건가?","JPN":"まさか、噂で聞いたゾディアックナイツの新入隊員か？","ENG":"Who are you, a newbie from the Zodiac Knights?","TWN":"還是她其實是我素未謀面的十二宮騎士團新團員？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"……그대들이 찾아낸 물건.","JPN":"……お前たちが見つけたモノ。","ENG":"The thing that you found.","TWN":"……只要把你們找到的那個東西乖乖地交出來，"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"그것만 순순히 넘긴다면 가문의 명예를 걸고 그대들을 해치지 않겠다.","JPN":"それを大人しく渡してくれたら、\\n一族の誇りにかけてお前たちを傷つけることはしない。","ENG":"Give it to me, and I will not harm you. I swear it on my family’s honor.","TWN":"我就以家族的名譽保證，讓你們毫髮無傷地離開這裡。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"노바급 리액터를……?","JPN":"ノヴァ級リアクターを……？","ENG":"You want the Nova-Class Reactor?","TWN":"你是說諾瓦反應爐……？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"꼬마 아가씨, 미안하지만 협박할 사람을 잘못 골랐어.","JPN":"お嬢ちゃん、悪いが脅迫する相手を間違えてるぞ？","ENG":"Girl, you picked the wrong person to threaten.","TWN":"我說小丫頭，不好意思喔，你惹錯人囉！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"어른들 일에 함부로 끼어들지 말라고 부모님께 배우지 않았나?","JPN":"大人のすることに首を突っ込んじゃいけないって、ご両親に教わらなかったかな？","ENG":"Didn’t your parents teach you to stay out of grown-ups’ businesses?","TWN":"而且你的爸爸媽媽沒有教你嗎？大人的事小孩別管！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"그런가……?","JPN":"そうなのか……？","ENG":"Is that so?","TWN":"是嗎……？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"안타깝게도 가문의 어른들 모두 일찍 돌아가셨기 때문에, 충분한 교육을 받을 기회가 없었다.","JPN":"残念ながら、我が一家の大人は皆早くに亡くなったので、\\n十分な教育を受ける機会が無かった。","ENG":"My parents passed away very early, so I didn’t really have the chance to get a proper education from them.","TWN":"很抱歉，家族的長輩們全都早逝，我沒有機會受到良好的家庭教育。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"그 가르침 감사히 기억해 두겠다.","JPN":"その教え、ありがたく覚えておこう。","ENG":"I appreciate your lesson.","TWN":"你這一番話我會銘記於心的。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이봐, 대령. 그러게 왜 괜한 소리를 해.","JPN":"おい、大佐。なんで余計なことを言うんだ。","ENG":"Colonel, you shouldn’t have said that.","TWN":"上校，你看你啦！誰叫你要說那些莫名其妙的話！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그쪽도 제이나에게 말실수했잖아! 무고한 척 하지 마!","JPN":"そっちだってジェイナに失礼なこと言っただろうが！\\n自分のことは棚にあげるの、やめろよな！","ENG":"You said the same thing to Jaina! I don’t want your lecture!","TWN":"拜託，你還不是有對婕娜亂說話！少在那邊裝無辜喔！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그랬었나?","JPN":"そんなことあったっけ？","ENG":"Did I?","TWN":"我哪有？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"아무튼 저 아가씨, 우릴 그냥 보내줄 생각은 없나 보군.","JPN":"とにかくあのお嬢ちゃん、素直に通すつもりはないようだ。","ENG":"Anyway, I don’t think that girl will let us go easily.","TWN":"總之，看來那個小丫頭沒有要放過我們的意思。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"이방인의 가르침은 고마우나, 나 역시 의무를 짊어진 몸.","JPN":"異邦人の教えはありがたいが、私も義務を背負った身。","ENG":"Though I appreciate your lesson, outsiders, I have a duty to perform.","TWN":"謝謝外邦人的教導，但我畢竟有要務在身。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"순순히 내놓지 않겠다면, 내 의무를 다하기 위해 힘으로 관철하겠다.","JPN":"大人しく渡さないのであれば、己の義務を果たすため、力でねじ伏せるのみ。","ENG":"If you resist, I will have to use force to meet my obligations.","TWN":"若你們不願意乖乖交出來，那我只好想方設法達成任務。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"잠깐, 저것들 어디서 나타난 거지? 방금 전까지 아무것도 없었는데?","JPN":"ちょっとまった。あいつらどこから現れたんだ？　さっきまで何も無かったぞ？","ENG":"Where did they come from? They just appeared!","TWN":"等等，那些傢伙是從哪裡冒出來的？剛剛周圍根本沒人啊？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그래. 무슨 유령 같군.","JPN":"ああ、まるで幽霊みたいだな。","ENG":"Yes, like ghosts.","TWN":"對啊，跟鬼一樣。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"준비해, 메이슨 씨. 총이든 창이든 맞으면 아픈 건 마찬가지니까.","JPN":"構えろ、メイソンさん。銃も槍も、当たれば痛いに決まってる。","ENG":"Get ready, Mr. Mason. Spears or guns, they will hurt you if you let them touch you.","TWN":"梅森，準備！不管是長槍還是手槍，被打到都是會痛的。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"……마르티네즈 백작가의 명예를 위해.","JPN":"……マルチネス伯爵家の名誉のために。","ENG":"In the honorable name of Martinez...","TWN":"……以馬汀尼茲伯爵家之名，"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_QM","text":{"KOREA":"전군, 돌격!","JPN":"全軍、突撃！","ENG":"Knights, charge!","TWN":"全軍出動！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};